	"schoolui/view/fragments/RequestDialog.fragment.xml":'<core:FragmentDefinition\n    xmlns="sap.m"\n    xmlns:core="sap.ui.core"><Dialog\n    id="requestDialog"\n    title="📜 Request Bonafide Certificate"\n    contentWidth="600px"\n    contentHeight="550px"\n    stretchOnPhone="true"\n    draggable="true"\n    resizable="true"><content><VBox class="sapUiMediumMargin"><Text\n                    text="Specify the purpose and recipient details"\n                    class="sapUiSmallMarginBottom"/><Label\n                    text="PURPOSE"\n                    required="true"\n                    class="sapUiTinyMarginBottom"/><Select\n                    id="dialogPurposeSelect"\n                    width="100%"\n                    class="sapUiMediumMarginBottom"><items><core:Item\n                            key="--Select--"\n                            text="--Select--"/><core:Item\n                            key="Bank Account Opening"\n                            text="Bank Account Opening"/><core:Item\n                            key="Passport Application"\n                            text="Passport Application"/><core:Item\n                            key="Education Loan"\n                            text="Education Loan"/><core:Item\n                            key="Scholarship"\n                            text="Scholarship"/><core:Item\n                            key="Visa Application"\n                            text="Visa Application"/><core:Item\n                            key="Others"\n                            text="Others"/></items></Select><Label\n                    text="STUDENT NAME"\n                    required="true"\n                    class="sapUiTinyMarginBottom"/><Input\n                    id="dialogIssuedTo"\n                    placeholder="Enter student name"\n                    liveChange="onNameLiveChange"\n                    class="sapUiMediumMarginBottom"/><Label\n                    text="STUDENT EMAIL"\n                    required="true"\n                    class="sapUiTinyMarginBottom"/><Input\n                    id="dialogStudentEmail"\n                    placeholder="Enter student email"\n                    liveChange="onEmailLiveChange"\n                    class="sapUiMediumMarginBottom"/><Label\n                    text="DEPARTMENT"\n                    required="true"\n                    class="sapUiTinyMarginBottom"/><Select\n                    id="dialogDepartment"\n                    width="100%"\n                    class="sapUiMediumMarginBottom"><items><core:Item\n                            key="--Select--"\n                            text="--Select Department--"/><core:Item\n                            key="Computer Science"\n                            text="Computer Science"/><core:Item\n                            key="Information Technology"\n                            text="Information Technology"/><core:Item\n                            key="Electronics"\n                            text="Electronics"/><core:Item\n                            key="Mechanical"\n                            text="Mechanical"/></items></Select><Label\n                    text="REMARKS"\n                    required="true"\n                    class="sapUiTinyMarginBottom"/><TextArea\n                     id="dialogRemarks"\n                     rows="8"\n                     growing="true"\n                     growingMaxLines="8"\n                     width="100%"\n                     placeholder="Additional details..."\n                     class="sapUiTinyMarginBottom"/><Label\n                    text="NUMBER OF COPIES"\n                    required="true"\n                    class="sapUiTinyMarginBottom"/><Select\n                    id="dialogCopiesSelect"\n                    width="100%"><items><core:Item\n                            key="1"\n                            text="1"/><core:Item\n                            key="2"\n                            text="2"/><core:Item\n                            key="3"\n                            text="3"/><core:Item\n                            key="4"\n                            text="4"/><core:Item\n                            key="5"\n                            text="5"/></items></Select></VBox></content><beginButton><Button\n                text="Cancel"\n                press="onCancelDialog"/></beginButton><endButton><Button\n                text="Submit Request"\n                type="Emphasized"\n                press="onSubmitRequest"/></endButton></Dialog></core:FragmentDefinition>'
